- Create a new file named `sort-by-numbers.js`
  and paste the following code:

  ```javascript
  const { MongoClient } = require("mongodb");

  // Replace the uri string with your MongoDB deployments connection string.
  const uri =
    "<connection-string>";

  const client = new MongoClient(uri);

  async function run() {
    try {
      await client.connect();

      // set namespace
      const database = client.db("sample_mflix");
      const coll = database.collection("movies");

      // define pipeline
      const agg = [
        {
          '$search': {
            'index': 'default',
            'range': {
              'path': 'awards.wins', 
              'gte': 10
            }, 
            'sort': {
              'awards.wins': -1
            }
          }
        }, {
          '$limit': 5
        }, {
          '$project': {
            '_id': 0, 
            'title': 1, 
            'awards.wins': 1
          }
        }
      ];

      // run pipeline
      const result = await coll.aggregate(agg);

      // print results
      await result.forEach((doc) => console.log(doc));

    } finally {
      await client.close();
    }
  }
  run().catch(console.dir);

  ```

- Specify the `<connection-string>`.

**Input:**

```bash
node sort-by-numbers.js
```

**Output:**

```json
{ title: '12 Years a Slave', awards: { wins: 267 } }
{ title: 'Gravity', awards: { wins: 231 } }
{ title: 'Gravity', awards: { wins: 231 } }
{
  title: 'Birdman: Or (The Unexpected Virtue of Ignorance)',
  awards: { wins: 210 }
}
{ title: 'Boyhood', awards: { wins: 185 } }
```

